// SPDX-License-Identifier: MIT
pragma solidity ^0.8.5;
contract Election {

    mapping(uint => uint) private mapa;
    uint num_regions; 
    address creador;
    uint numPartidos;
    modifier onlyAuthority (){
        require(msg.sender == msg.sender, "error");
        _;
    }
    modifier freshId(uint idRegion){
        require(mapa[idRegion] == 0, "ya existe esa region");
        _;
    }
    modifier validId(uint regionId){
        require(mapa[regionId] != 0, "ya existe");
        _;  
    }

    constructor(uint n){
        creador = msg.sender;
        numPartidos = n;
    }


}

